1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.10;
3	
4	const BLOCK_OF_THREE_PRICE = 60;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const BASE_PRICE: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	function surchargeFor(item: { type: string; cursed?: boolean; enchantment?: number }): number {
19	  let surcharge = 0;
20	  if (item.cursed) {
21	    surcharge += BASE_PRICE[item.type] * CURSED_SURCHARGE_RATE;
22	  }
23	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
24	    surcharge += BASE_PRICE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
25	  }
26	  return surcharge;
27	}
28	
29	function itemPremium(items: { type: string; cursed?: boolean; enchantment?: number }[]): number {
30	  const countsByType: Record<string, number> = {};
31	  for (const item of items) {
32	    countsByType[item.type] = (countsByType[item.type] || 0) + 1;
33	  }
34	
35	  let itemTotal = 0;
36	  for (const type in countsByType) {
37	    const count = countsByType[type];
38	    const isBlockOfThree = count === 3;
39	    if (isBlockOfThree) {
40	      itemTotal += BLOCK_OF_THREE_PRICE;
41	    } else {
42	      itemTotal += count * BASE_PRICE[type];
43	    }
44	  }
45	
46	  for (const item of items) {
47	    itemTotal += surchargeFor(item);
48	  }
49	
50	  return itemTotal + itemTotal * FIRST_INSURANCE_RATE;
51	}
52	
53	export function quote(
54	  policy: { customer: { years: number }; items: { type: string; cursed?: boolean; enchantment?: number }[] },
55	  _options: { isFollowUp: boolean }
56	): { premium: number } {
57	  return { premium: Math.ceil(itemPremium(policy.items) + PROCESSING_FEE) };
58	}
59	
60	export function claim(): undefined {
61	  return undefined;
62	}
63	
